final class FieldReaderAtomicBooleanReadOnly<T>
        extends FieldReader<T> {
    FieldReaderAtomicBooleanReadOnly(
            String fieldName,
            Class fieldClass,
            int ordinal,
            String format,
            AtomicBoolean defaultValue,
            JSONSchema schema,
            Method method,
            Field field
    ) {
        super(fieldName, fieldClass, fieldClass, ordinal, 0, format, null, defaultValue, schema, method, field);
    }

    @Override
    public boolean isReadOnly() {
        return true;
    }

    @Override
    public void accept(T object, Object value) {
        if (value == null) {
            return;
        }

        try {
            AtomicBoolean atomic = (AtomicBoolean) propertyAccessor.getObject(object);
            if (value instanceof AtomicBoolean) {
                value = ((AtomicBoolean) value).get();
            }
            atomic.set((Boolean) value);
        } catch (Exception e) {
            throw new JSONException("set " + fieldName + " error", e);
        }
    }

    @Override
    public void readFieldValue(JSONReader jsonReader, T object) {
        Boolean value = jsonReader.readBool();
        accept(object, value);
    }

    @Override
    public Object readFieldValue(JSONReader jsonReader) {
        return jsonReader.readBool();
    }
}

